def is_Monotonic(arr):
    if len(arr) <= 1:
        return True

    increasing = False
    decreasing = False

    for i in range(len(arr) - 1):
        if arr[i] < arr[i + 1]:
            increasing = True
        elif arr[i] > arr[i + 1]:
            decreasing = True
        else:
            # Equal elements don't affect monotonicity, but ensure we don't
            # incorrectly set flags if only one direction is possible
            pass

    # If both increasing and decreasing are True, it's not monotonic
    # unless the array is constant (which would have both True but no strict direction)
    # However, a constant array should be considered monotonic (both non-increasing and non-decreasing)
    # The logic above sets both flags for constant arrays, so we need to handle that.
    # Actually, for a constant array, no strict increase or decrease happens, so both flags remain False.
    # Let's re-evaluate: if we see any increase, increasing becomes True. If we see any decrease, decreasing becomes True.
    # If both are True, it's not monotonic. If only one or neither, it is monotonic.

    return not (increasing and decreasing)

