def is_samepatterns(patterns, pattern_map):
    """
    Check if the strings in 'patterns' follow the same substitution pattern as 'pattern_map'.

    Each character in 'pattern_map' must map to a unique string in 'patterns', and vice versa.
    This ensures a bijective mapping between the pattern characters and the pattern strings.

    Parameters:
        patterns (List[str]): The list of strings to check.
        pattern_map (List[str]): The list of pattern characters representing the sequence.

    Returns:
        bool: True if the strings follow the given pattern, False otherwise.
    """
    if len(patterns) != len(pattern_map):
        return False

    mapping = {}
    reverse_mapping = {}

    for pattern_char, word in zip(pattern_map, patterns):
        if pattern_char in mapping:
            if mapping[pattern_char] != word:
                return False
        else:
            if word in reverse_mapping:
                return False
            mapping[pattern_char] = word
            reverse_mapping[word] = pattern_char

    return True

