def sequence(n):
    if n == 1:
        return 1
    if n == 2:
        return 2

    # Initialize the sequence list with the first two numbers
    seq = [1, 2]

    # Generate the sequence up to the nth number
    for i in range(3, n + 1):
        # The rule for Newman Conway sequence:
        # a(n) = a(a(n-1)) if n-1 is even
        # a(n) = a(a(n-1)) + a(a(n-2)) if n-1 is odd
        prev = seq[-1]
        prev2 = seq[-2]

        if (i - 1) % 2 == 0:
            next_val = seq[seq[prev]]
        else:
            next_val = seq[seq[prev]] + seq[seq[prev2]]

        seq.append(next_val)

    return seq[n - 1]

