def pancake_sort(arr):
    n = len(arr)
    max_idx = 0

    for k in range(1, n + 1):
        # Find the maximum element in arr[0..k-1]
        for i in range(k):
            if arr[i] > arr[max_idx]:
                max_idx = i

        # If the maximum element is not in its correct position, move it
        if max_idx != k - 1:
            # If the maximum is not at the top, flip it to the top
            if max_idx != 0:
                arr = flip(arr, max_idx)
            # Now flip the top k elements to put the maximum at position k-1
            arr = flip(arr, k - 1)

    return arr

def flip(arr, k):
    """
    Flip the first k elements of the list.
    """
    return arr[:k][::-1] + arr[k:]

