def sequence(n):
    if n == 1:
        return 1

    # Build sequence up to n
    seq = [0] * (n + 1)
    seq[1] = 1

    for i in range(2, n + 1):
        seq[i] = seq[seq[i-1]] + seq[i - seq[i-1]]

    return seq[n]

