def sequence(n):
    if n <= 0:
        raise ValueError("n must be a positive integer")

    memo = {}

    def helper(k):
        if k in memo:
            return memo[k]

        if k == 1:
            memo[k] = 1
            return 1

        result = helper(helper(k - 1)) + helper(k - helper(k - 1))
        memo[k] = result
        return result

    return helper(n)

