def search(arr):
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        if mid % 2 == 0:
            # Mid is at an even position, so it should be the start of a pair
            if arr[mid] == arr[mid + 1]:
                left = mid + 2  # Unique element is to the right
            else:
                right = mid  # Unique element is to the left or at mid
        else:
            # Mid is at an odd position, so it should be the end of a pair
            if arr[mid] == arr[mid - 1]:
                right = mid - 2  # Unique element is to the left
            else:
                left = mid  # Unique element is to the right or at mid

    return arr[left]

