def search(arr):
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is the unique element
        if mid > 0 and arr[mid] == arr[mid - 1] and mid < len(arr) - 1 and arr[mid] == arr[mid + 1]:
            # mid is part of a pair, continue searching
            pass
        elif mid == 0 or arr[mid] != arr[mid - 1]:
            # Unique element is on the left side (including mid)
            right = mid
        elif mid == len(arr) - 1 or arr[mid] != arr[mid + 1]:
            # Unique element is on the right side (including mid)
            left = mid + 1
        else:
            # arr[mid] == arr[mid+1], unique element is on the right
            left = mid + 1

    return arr[left]

