def amicable_numbers_sum(n):
    def sum_divisors(num):
        if num <= 1:
            return 0
        sum_div = 1  # 1 is always a proper divisor
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                sum_div += i
                if i != num // i:
                    sum_div += num // i
        return sum_div

    amicable_numbers = set()
    for num in range(2, n + 1):
        other = sum_divisors(num)
        if other > num and other <= n:
            if sum_divisors(other) == num:
                amicable_numbers.add(num)
                amicable_numbers.add(other)

    return sum(amicable_numbers)

