def find_length(s):
    if not s:
        return 0

    max_diff = 0
    current_diff = 0

    for i in range(len(s)):
        if s[i] == '0':
            current_diff += 1
        else:
            current_diff -= 1

        max_diff = max(max_diff, current_diff)

    return max_diff

def find_length(s):
    if not s:
        return 0

    max_diff = 0
    prefix_0 = 0
    prefix_1 = 0

    for char in s:
        if char == '0':
            prefix_0 += 1
        else:
            prefix_1 += 1

        diff = abs(prefix_0 - prefix_1)
        max_diff = max(max_diff, diff)

    return max_diff

def find_length(s):
    n = len(s)
    max_diff = 0

    for i in range(n):
        count_0 = 0
        count_1 = 0
        for j in range(i, n):
            if s[j] == '0':
                count_0 += 1
            else:
                count_1 += 1
            diff = abs(count_0 - count_1)
            if diff > max_diff:
                max_diff = diff

    return max_diff

