def magic_square_test(matrix):
    # Check if matrix is square
    n = len(matrix)
    if len(matrix[0]) != n:
        return False

    # Check if all rows have the same length
    for row in matrix:
        if len(row) != n:
            return False

    # Check if all elements are integers
    for row in matrix:
        for num in row:
            if not isinstance(num, int):
                return False

    # Check if all elements are positive
    for row in matrix:
        for num in row:
            if num <= 0:
                return False

    # Check if all elements are distinct
    all_elements = []
    for row in matrix:
        all_elements.extend(row)

    if len(all_elements) != len(set(all_elements)):
        return False

    # Calculate the target sum from the first row
    target_sum = sum(matrix[0])

    # Check all row sums
    for row in matrix:
        if sum(row) != target_sum:
            return False

    # Check all column sums
    for col_idx in range(n):
        col_sum = sum(matrix[row][col_idx] for row in range(n))
        if col_sum != target_sum:
            return False

    # Check main diagonal sum
    main_diag_sum = sum(matrix[i][i] for i in range(n))
    if main_diag_sum != target_sum:
        return False

    # Check anti-diagonal sum
    anti_diag_sum = sum(matrix[i][n - 1 - i] for i in range(n))
    if anti_diag_sum != target_sum:
        return False

    return True

