def pancake_sort(arr):
    n = len(arr)
    arr = list(arr)  # Make a copy to avoid modifying the original

    for i in range(n, 1, -1):
        # Find the index of the maximum element in arr[:i]
        max_idx = i - 1
        for j in range(i - 1, -1, -1):
            if arr[j] > arr[max_idx]:
                max_idx = j

        # Flip the maximum element to the top if it's not already there
        if max_idx != 0:
            arr = pancake_flip(arr, max_idx + 1)

        # Flip the maximum element to its correct position if it's not already there
        if max_idx != i - 1:
            arr = pancake_flip(arr, i)

    return arr

