def bell_number(n):
    if n == 0:
        return 1

    # Initialize Bell triangle
    bell_triangle = [[0] * (n + 1)]
    bell_triangle[0].append(1)

    for i in range(1, n + 1):
        row = [0] * (i + 1)
        row[0] = bell_triangle[i-1][i-1]
        for j in range(1, i + 1):
            row[j] = bell_triangle[i-1][j-1] + row[j-1]
        bell_triangle.append(row)

    return bell_triangle[n][n]

def bell_number(n):
    """
    Calculate the Bell number for a given non-negative integer n.
    The Bell number B(n) is the number of ways to partition a set with n elements.
    """
    if n < 0:
        raise ValueError("n must be a non-negative integer")

    # Initialize the triangle
    # B(n, k) = number of ways to partition a set of n elements into k non-empty subsets
    triangle = [[0] * (i + 1) for i in range(n + 1)]
    triangle[0][0] = 1

    # Fill the triangle using recurrence relation
    for i in range(1, n + 1):
        triangle[i][0] = 0
        for j in range(1, i + 1):
            triangle[i][j] = sum(triangle[i-1][k] * binomial(i-1, j-1) for k in range(j))

    # Bell number is the sum of the last row
    return sum(triangle[n])

def binomial(n, k):
    """Calculate binomial coefficient C(n, k)"""
    if k < 0 or k > n:
        return 0
    if k == 0 or k == n:
        return 1
    if k > n // 2:
        k = n - k

    result = 1
    for i in range(k):
        result = result * (n - i) // (i + 1)
    return result

