def amicable_numbers_sum(n):
    def sum_divisors(num):
        if num <= 1:
            return 0
        total = 1
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                total += i
                if i != num // i:
                    total += num // i
        return total

    amicable_pairs = set()

    for i in range(1, n + 1):
        sum_i = sum_divisors(i)
        if sum_i != i and sum_i <= n:
            sum_sum_i = sum_divisors(sum_i)
            if sum_sum_i == i and i not in amicable_pairs and sum_i not in amicable_pairs:
                amicable_pairs.add(i)
                amicable_pairs.add(sum_i)

    return sum(amicable_pairs)

