def find_length(s: str) -> int:
    if not s:
        return 0

    max_diff = 0
    current_diff = 0

    # Calculate the difference between 0s and 1s at each position
    # We use cumulative difference: +1 for '0', -1 for '1'
    # Then we find the maximum difference between any two cumulative values

    # First, calculate cumulative differences
    diffs = [0]
    for char in s:
        if char == '0':
            diffs.append(diffs[-1] + 1)
        else:
            diffs.append(diffs[-1] - 1)

    # The maximum difference is the maximum difference between any two cumulative values
    # This represents the maximum difference between 0s and 1s in any substring
    for i in range(1, len(diffs)):
        max_diff = max(max_diff, diffs[i] - diffs[0])

    return max_diff

