    n = len(arr)
    for i in range(n):
        max_idx = i
        for j in range(i + 1, n):
            if arr[j] > arr[max_idx]:
                max_idx = j

        if max_idx != i:
            # Flip the max element to position i
            pancake_flip(arr, max_idx)
            # Flip the entire array up to position i
            pancake_flip(arr, i)

    return arr

