def bell_number(n):
    if n < 0:
        return 0

    # Initialize Bell triangle
    bell_triangle = [[0] * (n + 1) for _ in range(n + 1)]

    # Fill the first row
    bell_triangle[0][0] = 1

    # Fill the triangle
    for i in range(1, n + 1):
        bell_triangle[i][0] = bell_triangle[i-1][n-1]
        for j in range(1, i + 1):
            bell_triangle[i][j] = bell_triangle[i-1][j-1] + bell_triangle[i-1][j]

    return bell_triangle[n][0]

def bell_number(n):
    if n == 0:
        return 1

    # Initialize Stirling numbers table
    S = [[0] * (n + 1) for _ in range(n + 1)]
    S[0][0] = 1

    for i in range(1, n + 1):
        for j in range(1, i + 1):
            S[i][j] = j * S[i-1][j] + S[i-1][j-1]

    return sum(S[n])

def bell_number(n):
    """Calculate the nth Bell number (number of ways to partition a set of n elements)."""
    if n < 0:
        return 0
    if n == 0:
        return 1

    # Bell triangle (Aitken's array)
    bell_triangle = [[0] * (n + 1)]
    bell_triangle[0][0] = 1

    for i in range(1, n + 1):
        bell_triangle.append([0] * (i + 1))
        bell_triangle[i][0] = bell_triangle[i-1][i-1]
        for j in range(1, i + 1):
            bell_triangle[i][j] = bell_triangle[i-1][j-1] + bell_triangle[i][j-1]

    return bell_triangle[n][0]

