def is_samepatterns(first_list, second_list):
    """
    Check whether the two lists follow the same pattern.
    Each unique element in the first list should map to the same
    unique element in the second list, and vice versa.
    """
    if len(first_list) != len(second_list):
        return False

    mapping = {}
    reverse_mapping = {}

    for i in range(len(first_list)):
        first = first_list[i]
        second = second_list[i]

        # Check if first element has been mapped before
        if first in mapping:
            if mapping[first] != second:
                return False
        else:
            mapping[first] = second

        # Check if second element has been mapped before (to ensure bijection)
        if second in reverse_mapping:
            if reverse_mapping[second] != first:
                return False
        else:
            reverse_mapping[second] = first

    return True

