def merge_dictionaries_three(dict1, dict2, dict3):
    """
    Merge three dictionaries into a single dictionary.
    Later dictionaries override earlier ones for duplicate keys.
    """
    return {**dict1, **dict2, **dict3}

def merge_dictionaries_three(d1, d2, d3):
    """
    Merge three dictionaries into a single dictionary.
    If a key appears in multiple dictionaries, the value from the last dictionary takes precedence.
    """
    result = {}
    for k, v in d1.items():
        result[k] = v
    for k, v in d2.items():
        result[k] = v
    for k, v in d3.items():
        result[k] = v
    return result

