def is_undulating(n):
    """
    Check if a number is undulating (digits alternate between increasing and decreasing).

    An undulating number has digits that alternate between increasing and decreasing.
    For example: 1212121, 12321 (wait, 12321 doesn't alternate properly)
    """
    s = str(n)
    if len(s) < 2:
        return True

    # Check if digits alternate between increasing and decreasing
    for i in range(len(s) - 1):
        current = s[i]
        next_char = s[i + 1]

        if current < next_char:
            # Increasing, next should be decreasing
            if i > 0 and s[i - 1] <= s[i]:
                return False
        else:
            # Decreasing, next should be increasing
            if i > 0 and s[i - 1] >= s[i]:
                return False

    return True

