def snake_to_camel(snake_case):
    if not snake_case:
        return ''

    # Capitalize the first letter
    result = snake_case[0].upper() + snake_case[1:]

    # Iterate through the string and capitalize letters after underscores
    for i in range(1, len(result)):
        if result[i-1] == '_' and result[i].isalpha():
            result = result[:i] + result[i].upper() + result[i+1:]

    return result

