def find_unique_element(arr):
    left, right = 0, len(arr) - 1

    while left <= right:
        mid = (left + right) // 2

        # Check if mid is at an even position
        if mid % 2 == 0:
            if mid + 1 < len(arr) and arr[mid] == arr[mid + 1]:
                # Pair starts at mid, unique element is to the right
                left = mid + 2
            else:
                # Pair ends at mid, unique element is to the left
                right = mid - 1
        else:
            # mid is at an odd position
            if mid - 1 >= 0 and arr[mid - 1] == arr[mid]:
                # Pair ends at mid, unique element is to the left
                right = mid - 2
            else:
                # Pair starts at mid, unique element is to the right
                left = mid + 1

    return arr[left] if left < len(arr) else None

def find_single_element(arr):
    """
    Find the element that appears only once in a sorted array.
    Most elements appear twice, one element appears once.
    """
    n = len(arr)
    if n == 0:
        return None

    # Binary search approach for O(log n) time complexity
    left, right = 0, n - 1

    while left < right:
        mid = (left + right) // 2

        # Ensure mid is even to check with next element
        if mid % 2 == 0:
            if arr[mid] == arr[mid + 1]:
                left = mid + 2
            else:
                right = mid
        else:
            # mid is odd, check with previous element
            if arr[mid] == arr[mid - 1]:
                left = mid + 1
            else:
                right = mid - 1

    return arr[left]

def search(arr):
    left, right = 0, len(arr) - 1

    while left < right:
        mid = left + (right - left) // 2

        # If mid is even, check if mid and mid+1 are the same
        if mid % 2 == 0 and arr[mid] == arr[mid + 1]:
            left = mid + 1
        else:
            right = mid

    return arr[left]

