    while left <= right:
        mid = (left + right) // 2
        if mid % 2 == 0:
            # Check if mid and mid+1 are the same (paired)
            if mid + 1 < len(nums) and nums[mid] == nums[mid + 1]:
                # Unique element is to the right
                left = mid + 2
            else:
                # Unique element is at mid or to the left
                right = mid - 1
        else:
            # mid is odd, check if mid and mid-1 are the same (paired)
            if mid - 1 >= 0 and nums[mid] == nums[mid - 1]:
                # Unique element is to the left
                right = mid - 2
            else:
                # Unique element is at mid
                return nums[mid]
    return nums[left] if left < len(nums) else None

