def amicable_numbers_sum(n):
    """
    Calculate the sum of all amicable numbers up to n.

    Two different numbers are amicable if the sum of proper divisors 
    of each equals the other number.

    Args:
        n: The upper limit (inclusive) to search for amicable numbers

    Returns:
        The sum of all amicable numbers found up to n
    """
    def sum_divisors(num):
        """Calculate the sum of proper divisors of a number."""
        if num <= 1:
            return 0
        sum_div = 1  # 1 is always a proper divisor
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                sum_div += i
                if i != num // i:
                    sum_div += num // i
        return sum_div

    amicable_numbers = set()
    for num in range(2, n + 1):
        other = sum_divisors(num)
