def magic_square_test(matrix):
    # Check if matrix is a square matrix
    if not matrix or not all(len(row) == len(matrix[0]) for row in matrix):
        return False

    n = len(matrix)

    # Check if all elements are unique (no duplicates)
    all_elements = []
    for row in matrix:
        all_elements.extend(row)

    if len(all_elements) != len(set(all_elements)):
        return False

    # Calculate the expected sum from the first row
    expected_sum = sum(matrix[0])

    # Check all rows have the same sum
    for row in matrix:
        if sum(row) != expected_sum:
            return False

    # Check all columns have the same sum
    for col_idx in range(n):
        col_sum = sum(matrix[row_idx][col_idx] for row_idx in range(n))
        if col_sum != expected_sum:
            return False

    # Check main diagonal has the same sum
    main_diag_sum = sum(matrix[row_idx][row_idx] for row_idx in range(n))
    if main_diag_sum != expected_sum:
        return False

    # Check anti-diagonal has the same sum
    anti_diag_sum = sum(matrix[row_idx][n - 1 - row_idx] for row_idx in range(n))
    if anti_diag_sum != expected_sum:
        return False

    return True

