def magic_square_test(matrix):
    """
    Check if a matrix is a magic square.

    A magic square is a square matrix where:
    1. All numbers are distinct and range from 1 to n^2 (where n is the size)
    2. All rows, columns, and diagonals sum to the same value
    """
    # Check if matrix is square
    if not matrix:
        return False

    n = len(matrix)

    # Check if all rows have the same length
    for row in matrix:
        if len(row) != n:
            return False

    # Check if matrix is square with size n
    if n < 1:
        return False

    # Check if all elements are distinct and range from 1 to n^2
    expected = set(range(1, n * n + 1))
    actual = set()

    for row in matrix:
        for num in row:
            if num not in expected:
                return False
            actual.add(num)

    if len(actual) != n * n:
        return False

    # Calculate the magic constant (sum of first row)
    magic_sum = sum(matrix[0])

    # Check all rows
    for row in matrix:
        if sum(row) != magic_sum:
            return False

    # Check all columns
    for col_idx in range(n):
        col_sum = sum(matrix[row][col_idx] for row in range(n))
        if col_sum != magic_sum:
            return False

    # Check main diagonal
    main_diag_sum = sum(matrix[i][i] for i in range(n))
    if main_diag_sum != magic_sum:
        return False

    # Check anti-diagonal
    anti_diag_sum = sum(matrix[i][n - 1 - i] for i in range(n))
    if anti_diag_sum != magic_sum:
        return False

    return True

