def find_solution(a, b, n):
    """
    Find integers x and y such that ax + by = n.

    Returns (x, y) if a solution exists, otherwise None.
    Based on Bézout's identity: solutions exist if and only if gcd(a, b) divides n.
    """
    def extended_gcd(a, b):
        if a == 0:
            return b, 0, 1
        else:
            g, y, x = extended_gcd(b % a, a)
            return g, x - (b // a) * y, y

    g, x, y = extended_gcd(a, b)

    if n % g != 0:
        return None

    x *= n // g
    y *= n // g
    return (x, y)

