def is_samepatterns(patterns):
    """
    Check if the given list follows the sequence given in the patterns array.

    Args:
        patterns: A list of strings representing the pattern to check

    Returns:
        bool: True if the sequence matches the pattern, False otherwise
    """
    if not patterns:
        return True

    # Create a mapping from pattern characters to unique values
    pattern_map = {}
    unique_counter = 0

    for i in range(len(patterns)):
        char = patterns[i]

        # If we've seen this character before, it must map to the same value
        if char in pattern_map:
            if pattern_map[char] != unique_counter:
                return False
        else:
            pattern_map[char] = unique_counter
            unique_counter += 1

    # Check if all values in the list are unique (they should map to unique pattern values)
    for i in range(len(patterns)):
        if patterns[i] not in pattern_map:
            return False

    # Verify that the actual values match the pattern structure
    pattern_values = [patterns[i] for i in range(len(patterns))]
    unique_values = set(pattern_values)

    if len(unique_values) != len(patterns):
        return False

    return True

