def next_smallest_palindrome(n):
    """
    Find the next smallest palindrome greater than or equal to n.
    Returns the palindrome as an integer.
    """
    n = int(n)

    # Check if n itself is a palindrome
    def is_palindrome(x):
        s = str(x)
        return s == s[::-1]

    # If n is already a palindrome, return the next one
    if is_palindrome(n):
        return next_smallest_palindrome(n + 1)

    # Start searching from n + 1
    candidate = n + 1
    while True:
        if is_palindrome(candidate):
            return candidate
        candidate += 1

