    """
    Count the number of times the binary string has an odd number of 1s
    when rotated n times.
    """
    def count_ones(rotated):
        return sum(int(bit) for bit in rotated)

    def rotate_left(s, k):
        k = k % len(s)
        if k == 0:
            return s
        return s[k:] + s[:k]

    count = 0
    for i in range(n + 1):
        if count_ones(rotate_left(s, i)):
            count += 1

    return count

