def amicable_numbers_sum(n):
    def get_sum_of_divisors(num):
        return sum(i for i in range(1, num // 2 + 1) if num % i == 0)

    def is_amicable(a, b):
        return a != b and get_sum_of_divisors(a) == b and get_sum_of_divisors(b) == a

    sum_amicable = 0
    for num in range(1, n + 1):
        # Skip if num is 1 (not amicable)
        if num == 1:
            continue
        # Check if num is amicable with another number
        partner = get_sum_of_divisors(num)
        if partner != num and partner <= n:
            # Check if partner is amicable with num
            if is_amicable(num, partner):
                # Add each amicable pair only once
                if num < partner:
                    sum_amicable += num
                elif partner < num:
                    sum_amicable += partner

    return sum_amicable

