        return False

    # Check if all characters are either lowercase letters or underscores
    import re
    pattern = r'^[a-z_]+$'
    if not re.match(pattern, text):
        return False

    # Check that there are actual underscores and at least two sequences of lowercase letters
    if '_' not in text:
        return False

    # Split by underscore and check all parts are non-empty lowercase sequences
    parts = text.split('_')
    if not parts:
        return False

    for part in parts:
        if not part:
            return False
        if not part.isalpha():
            return False

    return True

