def is_woodall(n):
    """
    Check if a number is a Woodall number.
    Woodall numbers are defined as W(n) = n * 2^n - 1 for n >= 1.
    """
    if not isinstance(n, int) or n <= 0:
        return False

    i = 1
    while True:
        woodall = i * (2 ** i) - 1
        if woodall == n:
            return True
        if woodall > n:
            return False
        i += 1

