def is_samepatterns(patterns, input_list):
    # Check if lengths match
    if len(patterns) != len(input_list):
        return False

    # Create mappings to ensure one-to-one correspondence
    pattern_to_input = {}
    input_to_pattern = {}

    for pattern, input_str in zip(patterns, input_list):
        # Check if pattern is already mapped to a different input
        if pattern in pattern_to_input:
            if pattern_to_input[pattern] != input_str:
                return False
        else:
            pattern_to_input[pattern] = input_str

        # Check if input is already mapped to a different pattern
        if input_str in input_to_pattern:
            if input_to_pattern[input_str] != pattern:
                return False
        else:
            input_to_pattern[input_str] = pattern

    return True

