    """
    Check whether a number is undulating.
    An undulating number alternates between increasing and decreasing digits.
    """
    digits = str(n)
    if len(digits) < 2:
        return False

    # Check for equal consecutive digits
    for i in range(len(digits) - 1):
        if digits[i] == digits[i+1]:
            return False

    # Check for alternating increasing/decreasing pattern
    for i in range(len(digits) - 2):
        if (digits[i] < digits[i+1]) != (digits[i+1] < digits[i+2]):
            return False

    return True

