    result = list(s)
    vowel_indices = [i for i, c in enumerate(s) if c in vowels]

    for i in range(len(vowel_indices) // 2):
        j = len(vowel_indices) - 1 - i
        result[vowel_indices[i]], result[vowel_indices[j]] = result[vowel_indices[j]], result[vowel_indices[i]]

    return ''.join(result)

