    """
    Check whether the strings in patterns follow the same pattern as in pattern_mapping.

    Args:
        patterns: List of strings to check
        pattern_mapping: List of single characters representing the pattern

    Returns:
        bool: True if patterns match the pattern, False otherwise
    """
    if len(patterns) != len(pattern_mapping):
