def sequence(n):
    if n == 1:
        return 1
    if n == 2:
        return 2

    # Start with previous values
    prev = [0] * (n + 1)
    prev[1] = 1
    prev[2] = 2

    # Generate sequence using Newman Conway rule
    for i in range(3, n + 1):
        prev[i] = prev[prev[i-1]] + prev[i - prev[i-1]]

    return prev[n]

