    def get_sum_of_proper_divisors(num):
        if num <= 1:
            return 0
        divisors = set()
        for i in range(1, int(num ** 0.5) + 1):
            if num % i == 0:
                divisors.add(i)
                if i != num // i and i != 1:
                    divisors.add(num // i)
                elif i == 1 and num // i == num:
                    divisors.add(num)
        return sum(divisors)

    seen = set()
    total = 0

    for num in range(1, n + 1):
        sum_num = get_sum_of_proper_divisors(num)
        if sum_num == num:
            continue

        sum_other = get_sum_of_proper_divisors(sum_num)
        if sum_other == num and num in seen:
            continue

        if sum_other == num and num not in seen:
            total += num + sum_other
            seen.add(num)
            seen.add(sum_other)

    return total

def amicable_numbers_sum(limit):
    """
    Sum all amicable numbers from 1 to a specified number.

    Args:
        limit (int): The upper bound (inclusive) for checking amicable numbers.

    Returns:
        int: The sum of all amicable numbers up to the limit.
    """

    def get_divisor_sum(n):
        """Calculate the sum of proper divisors of n."""
        if n <= 1:
            return 0
        divisors = 1
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                divisors += i
                if i != n // i:
                    divisors += n // i
        return divisors

    def is_amicable(a, b):
        """Check if two numbers are amicable."""
        if a == b:
            return False
        sum_a = get_divisor_sum(a)
        sum_b = get_divisor_sum(b)
        return sum_a == b and sum_b == a and a < b

    amicable_numbers = set()

    for num in range(1, limit + 1):
        sum_num = get_divisor_sum(num)
        if sum_num != num and sum_num < limit + 1:
            if is_amicable(num, sum_num):
                if num <= limit:
                    amicable_numbers.add(num)
                if sum_num <= limit:
                    amicable_numbers.add(sum_num)

    return sum(amicable_numbers)

