def magic_square_test(matrix):
    n = len(matrix)

    # Check if matrix is square
    if len(matrix[0]) != n:
        return False

    # Check if all elements are distinct and in range 1 to n^2
    flattened = [matrix[i][j] for i in range(n) for j in range(n)]
    if len(set(flattened)) != n * n:
        return False

    # Check if all elements are in range 1 to n^2
    if any(x <= 0 or x > n * n for x in flattened):
        return False

    # Calculate the target sum (sum of 1 to n^2)
    target_sum = n * (n * n + 1) // 2

    # Check if all rows sum to target
    for row in matrix:
        if sum(row) != target_sum:
            return False

    # Check if all columns sum to target
    for col in range(n):
        col_sum = sum(matrix[row][col] for row in range(n))
        if col_sum != target_sum:
            return False

    # Check if main diagonal sums to target
    main_diag_sum = sum(matrix[i][i] for i in range(n))
    if main_diag_sum != target_sum:
        return False

    # Check if anti-diagonal sums to target
    anti_diag_sum = sum(matrix[i][n - 1 - i] for i in range(n))
    if anti_diag_sum != target_sum:
        return False

    return True

