def bell_number(n):
    if n < 0:
        return 0
    if n == 0:
        return 1

    # Calculate Stirling numbers of the second kind
    # S(n, k) = k * S(n-1, k) + S(n-1, k-1)

    # Use dynamic programming to compute Stirling numbers
    S = [[0] * (n + 1) for _ in range(n + 1)]
    S[0][0] = 1

    for i in range(1, n + 1):
        for j in range(1, i + 1):
            S[i][j] = j * S[i-1][j] + S[i-1][j-1]

    # Bell number is the sum of Stirling numbers in row n
    return sum(S[n])

def bell_number(n):
    if n < 0:
        return 0
    if n == 0:
        return 1

    # Initialize a table for Stirling numbers of the second kind
    S = [[0] * (n + 1) for _ in range(n + 1)]
    S[0][0] = 1

    for i in range(1, n + 1):
        for j in range(1, i + 1):
            S[i][j] = j * S[i - 1][j] + S[i - 1][j - 1]

    # Bell number is the sum of Stirling numbers in the last row
    return sum(S[n][j] for j in range(n + 1))

