def eulerian_num(n, m):
    if m < 0 or m >= n:
        return 0
    if n == 0:
        return 1

    # Use dynamic programming with the recurrence relation
    # A(n, m) = (m+1) * A(n-1, m) + (n-m) * A(n-1, m-1)

    # Initialize table
    dp = [[0 for _ in range(n)] for _ in range(n)]

    # Base case
    dp[0][0] = 1

    for i in range(1, n + 1):
        for j in range(i):
            dp[i][j] = (j + 1) * dp[i - 1][j] + (i - j) * dp[i - 1][j - 1]

    return dp[n][m]

