def search_unique(arr):
    """
    Find the unique element in a sorted array where all other elements appear twice.
    Uses binary search for O(log n) time complexity.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is the second element of a pair
        if mid % 2 == 0:
            # mid should match mid+1 if it's a pair
            if arr[mid] == arr[mid + 1]:
                left = mid + 2
            else:
                right = mid
        else:
            # mid should match mid-1 if it's a pair
            if arr[mid] == arr[mid - 1]:
                left = mid + 1
            else:
                right = mid

    return arr[left]

