def amicable_numbers_sum(n):
    """
    Find the sum of all amicable numbers from 1 to n.

    Amicable numbers are pairs (a, b) where the sum of proper divisors
    of a equals b, and the sum of proper divisors of b equals a.
    """
    def get_sum_of_proper_divisors(num):
        if num <= 1:
            return 0
        sum_divs = 1  # 1 is always a proper divisor for num > 1
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                sum_divs += i
                if i != num // i:
                    sum_divs += num // i
        return sum_divs

    amicable_numbers = set()
    for num in range(2, n + 1):
        other = get_sum_of_proper_divisors(num)
        if other > num and other <= n:
            if get_sum_of_proper_divisors(other) == num:
                amicable_numbers.add(num)
                amicable_numbers.add(other)

    return sum(amicable_numbers)

