def is_majority(arr, n, element):
    """
    Check if the given element is a majority element in a sorted array.
    A majority element appears more than n/2 times.
    """
    if n == 0:
        return False

    # In a sorted array, majority element must be at index n//2
    if arr[n // 2] != element:
        return False

    # Find first occurrence of element
    left, right = 0, n - 1
    first = -1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] >= element:
            right = mid - 1
        else:
            left = mid + 1
        if arr[mid] == element and first == -1:
            first = mid

    # Find last occurrence of element
    left, right = 0, n - 1
    last = -1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] <= element:
            left = mid + 1
        else:
            right = mid - 1
        if arr[mid] == element and last == -1:
            last = mid

    count = last - first + 1
    return count > n / 2

