def bell_number(n):
    """
    Calculate the Bell number for n, which is the number of ways to partition a set of n elements.

    Bell numbers can be computed using the Bell triangle or the Bell numbers recurrence.
    B(n) = sum(B(n-1, k)) for k from 0 to n-1, where B(n, k) is the Stirling numbers of the second kind.
    """
    if n < 0:
        return 0
    if n == 0:
        return 1

    # Initialize a 2D array for Stirling numbers of the second kind
    S = [[0] * (n + 1) for _ in range(n + 1)]
    S[0][0] = 1

    # Fill the table
    for i in range(1, n + 1):
        for j in range(1, i + 1):
            S[i][j] = S[i-1][j-1] + S[i-1][j] if j > 0 else 0

    # Calculate Bell number as sum of row n-1
    return sum(S[n-1])

