def is_woodall(n):
    """
    Check if the given number is a Woodall number.
    A Woodall number is defined by the formula W_n = n * 2^n - 1.
    """
    if n < 1:
        return False

    i = 1
    while True:
        val = i * (2 ** i) - 1
        if val == n:
            return True
        if val > n:
            return False
        i += 1

