def bell_number(n):
    if n < 0:
        return 0
    if n == 0:
        return 1

    # Calculate Stirling numbers of the second kind
    # S[i][j] = S(i-1, j-1) + j * S(i-1, j)
    S = [[0] * (n + 1) for _ in range(n + 1)]
    S[0][0] = 1

    for i in range(1, n + 1):
        for j in range(1, i + 1):
            S[i][j] = S[i-1][j-1] + j * S[i-1][j]

    # Bell number B(n) = sum of S(n, k) for k from 1 to n
    result = sum(S[n][k] for k in range(1, n + 1))
    return result

def is_Monotonic(arr):
    if len(arr) <= 1:
        return True

    # Check if non-decreasing (each element >= previous)
    is_non_decreasing = True
    for i in range(1, len(arr)):
        if arr[i] < arr[i-1]:
            is_non_decreasing = False
            break

    # Check if non-increasing (each element <= previous)
    is_non_increasing = True
    for i in range(1, len(arr)):
        if arr[i] > arr[i-1]:
            is_non_increasing = False
            break

    return is_non_decreasing or is_non_increasing

