    if len(patterns) != len(pattern):
        return False

    mapping = {}
    used_values = set()

    for i in range(len(patterns)):
        if patterns[i] in mapping:
            if mapping[patterns[i]] != pattern[i]:
                return False
        else:
            if pattern[i] in used_values:
                return False
            mapping[patterns[i]] = pattern[i]
            used_values.add(pattern[i])

    return True

