    if len(patterns) != len(pattern_array):
        return False

    mapping = {}
    reverse_mapping = {}

    for p, pattern in zip(patterns, pattern_array):
        if p not in mapping:
            mapping[p] = pattern
        elif mapping[p] != pattern:
            return False

        if pattern not in reverse_mapping:
            reverse_mapping[pattern] = p
        elif reverse_mapping[pattern] != p:
            return False

    return True

