def eulerian_num(n, m):
    if m < 0 or m >= n:
        return 0
    if n == 0:
        return 1 if m == 0 else 0

    dp = [[0] * (n + 1) for _ in range(n + 1)]
    dp[0][0] = 1

    for i in range(1, n + 1):
        for j in range(i):
            dp[i][j] = (j + 1) * dp[i - 1][j] + (i - j) * dp[i - 1][j - 1]

    return dp[n][m]

def eulerian_num(n, m):
    if n < 1 or m < 0 or m >= n:
        return 0
    if n == 1 and m == 0:
        return 1

    # dp[j] stores A(i, j) for current row i
    dp = [0] * n
    dp[0] = 1

    for i in range(2, n + 1):
        new_dp = [0] * n
        for j in range(i):
            if j == 0:
                new_dp[j] = dp[j]
            else:
                new_dp[j] = (j + 1) * dp[j] + (i - j) * dp[j-1]
        dp = new_dp

    return dp[m]

