def amicable_numbers_sum(n):
    def sum_divisors(num):
        if num <= 1:
            return 0
        if num == 2:
            return 1
        if num == 3:
            return 1

        total = 1  # Start with 1 (always a proper divisor for num > 1)
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                total += i
                if i != num // i and num // i != num:
                    total += num // i

        return total

    result = 0
    for i in range(1, n + 1):
        sd_i = sum_divisors(i)

        # Skip if i is perfect (sum of divisors equals itself)
        if sd_i == i:
            continue

        # Skip if sd_i is not in range or doesn't form a valid pair
        if sd_i > i or sd_i > n:
            continue

        # Check if sd_i and i form an amicable pair
        sd_sd_i = sum_divisors(sd_i)
        if sd_sd_i == i:
            # Only count if i < sd_i to avoid double counting
            if i < sd_i:
                result += i

    return result

