def eulerian_num(n, m):
    if n < 0 or m < 0 or m > n:
        return 0
    if n == 0:
        return 1 if m == 0 else 0

    # dp[i][j] = number of permutations of length i with exactly j ascents
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    dp[0][0] = 1

    for i in range(1, n + 1):
        for j in range(i):
            # Add the element i to position j (0-indexed)
            # This creates j ascents from previous, and 1 or 0 new ascent
            dp[i][j] += dp[i-1][j] * (i - 1)
            dp[i][j] += dp[i-1][j-1]

    return dp[n][m]

