    # Calculate the effective number of rotations
    n = n % length

    if n == 0:
        return sum(int(c) % 2 for c in binary_string)

    # Calculate the count of odd numbers (1s) in the original string
    original_ones = sum(int(c) for c in binary_string)

    # For each rotation, count the number of 1s
    total_odd_count = 0
    for i in range(n + 1):
        rotated = binary_string[i:] + binary_string[:i]
        total_odd_count += sum(int(c) for c in rotated)

    return total_odd_count

