        return 0

    # Calculate the effective number of rotations (mod length)
    effective_rotations = n % length

    # Count odd values in each rotation
    count = 0
    for i in range(effective_rotations):
        rotated = s[i:] + s[:i]
        for char in rotated:
            if char == '1':
                count += 1
                break  # Count once per rotation

    return count

