        if num < 2:
            return 0
        total = 1
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                total += i
                if i != num // i:
                    total += num // i
        return total

    seen = set()
    result = 0

    for i in range(1, n + 1):
        if i in seen:
            continue
        a = sum_proper_divisors(i)
        if a == 0:
            continue
        b = sum_proper_divisors(a)
        if a != b:
            continue
        if sum_proper_divisors(b) == i:
            if i != b:
                seen.add(i)
                seen.add(b)
                result += i + b

    return result

def amicable_numbers_sum(n):
    def sum_divisors(num):
        if num <= 1:
            return 0
        total = 1
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                total += i
                if i != num // i:
                    total += num // i
        return total

    def is_amicable(a, b):
        return a != b and sum_divisors(a) == b and sum_divisors(b) == a

    total_sum = 0
    for i in range(1, n + 1):
        a = sum_divisors(i)
        if a != i and a <= n and sum_divisors(a) == i:
            if not is_amicable(i, a):
                total_sum += i
    return total_sum

