def amicable_numbers_sum(n):
    def sum_of_proper_divisors(num):
        if num <= 1:
            return 0
        total = 1  # 1 is always a proper divisor for num > 1
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                total += i
                if i != num // i:
                    total += num // i
        return total

    def is_amicable(a, b):
        if a == b:
            return False
        return sum_of_proper_divisors(a) == b and sum_of_proper_divisors(b) == a

    result = 0
    for i in range(1, n + 1):
        if sum_of_proper_divisors(i) > n and i > sum_of_proper_divisors(sum_of_proper_divisors(i)):
            if sum_of_proper_divisors(sum_of_proper_divisors(i)) == i:
                continue
        if sum_of_proper_divisors(i) != i and sum_of_proper_divisors(sum_of_proper_divisors(i)) == i:
            if sum_of_proper_divisors(sum_of_proper_divisors(i)) != i:
                continue
            if i < sum_of_proper_divisors(i):
                continue
            if i < n and sum_of_proper_divisors(i) <= n:
                result += i

    return result

