def magic_square_test(matrix):
    n = len(matrix)

    # Check if matrix is square
    if n != len(matrix[0]):
        return False

    # Check if matrix is non-empty
    if n == 0:
        return True

    # Calculate the expected sum for a magic square of size n
    expected_sum = n * (n * n + 1) // 2

    # Check if all elements are distinct and in range [1, n^2]
    elements = []
    for row in matrix:
        for elem in row:
            elements.append(elem)

    if len(elements) != n * n:
        return False

    if set(elements) != set(range(1, n * n + 1)):
        return False

    # Check all rows
    for row in matrix:
        if sum(row) != expected_sum:
            return False

    # Check all columns
    for col in range(n):
        column_sum = sum(matrix[row][col] for row in range(n))
        if column_sum != expected_sum:
            return False

    # Check main diagonal
    main_diag_sum = sum(matrix[i][i] for i in range(n))
    if main_diag_sum != expected_sum:
        return False

    # Check anti-diagonal
    anti_diag_sum = sum(matrix[i][n - 1 - i] for i in range(n))
    if anti_diag_sum != expected_sum:
        return False

    return True

