    """
    Check if a matrix is a magic square.

    A magic square is an n x n matrix where:
    1. Contains all integers from 1 to n^2 exactly once
    2. All rows sum to the same value
    3. All columns sum to the same value
    4. Both main diagonals sum to the same value
    """
    n = len(matrix)

    # Handle edge cases
    if n == 0:
        return False

    # Check if matrix is square
    for row in matrix:
        if len(row) != n:
            return False

    # Check if all elements are within range 1 to n^2
    expected_max = n * n
    for row in matrix:
        for val in row:
            if val < 1 or val > expected_max:
                return False

    # Check if all elements are distinct
    elements = []
    for row in matrix:
        elements.extend(row)

    if len(elements) != len(set(elements)):
        return False

    # Calculate the magic constant (sum of first row)
    magic_sum = sum(matrix[0])

    # Check all rows sum to magic_sum
    for row in matrix:
        if sum(row) != magic_sum:
            return False

    # Check all columns sum to magic_sum
    for col_idx in range(n):
        col_sum = sum(matrix[row][col_idx] for row in range(n))
        if col_sum != magic_sum:
            return False

    # Check main diagonal sums to magic_sum
    main_diag_sum = sum(matrix[i][i] for i in range(n))
    if main_diag_sum != magic_sum:
        return False

    # Check anti-diagonal sums to magic_sum
    anti_diag_sum = sum(matrix[i][n - 1 - i] for i in range(n))
    if anti_diag_sum != magic_sum:
        return False

    return True

