def zero_count(arr):
    zeroes = 0
    non_zeroes = 0
    for num in arr:
        if num == 0:
            zeroes += 1
        else:
            non_zeroes += 1
    if non_zeroes == 0:
        return 0.0
    return zeroes / non_zeroes

import math

def zero_count(arr):
    if not arr:
        return 0.0
    zeroes = sum(1 for x in arr if x == 0)
    non_zeroes = sum(1 for x in arr if x != 0)
    return zeroes / (zeroes + non_zeroes)

def is_Sum_Of_Powers_Of_Two(n):
    if n <= 0:
        return False
    while n > 0:
        if n % 2 == 0:
            n //= 2
        else:
            return True
    return True

