def is_majority(arr, n, element):
    if n == 0:
        return False

    # Find the first occurrence of the element
    left = 0
    right = n - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] < element:
            left = mid + 1
        elif arr[mid] > element:
            right = mid - 1
        else:
            # Found the element, now find first occurrence
            first = mid
            while first > 0 and arr[first - 1] == element:
                first -= 1
            break

    if arr[first] != element:
        return False

    # Find the last occurrence of the element
    right = n - 1
    while right >= 0:
        mid = (left + right) // 2
        if arr[mid] < element:
            left = mid + 1
        elif arr[mid] > element:
            right = mid - 1
        else:
            # Found the element, now find last occurrence
            last = mid
            while last < n - 1 and arr[last + 1] == element:
                last += 1
            break

    # Check if the element is the majority element
    return (last - first) > n // 2

