def bell_number(n):
    if n < 0:
        return 0
    if n == 0:
        return 1

    # Initialize Bell triangle
    bell = [1]
    for i in range(1, n + 1):
        row = [0] * (i + 1)
        row[0] = bell[-1]
        for j in range(1, i + 1):
            row[j] = row[j-1] + bell[j-1]
        bell.append(row[-1])

    return bell[n]

