        return False

    # Check if each adjacent pair alternates direction
    for i in range(len(digits) - 1):
        current = int(digits[i])
        next_digit = int(digits[i + 1])

        # Check if adjacent digits are the same
        if current == next_digit:
            return False

        # Check if the direction alternates
        if i > 0:
            # If current direction is same as previous, return False
            if (current > next_digit) == (digits[i-1] > digits[i]):
                return False

    return True

