    while left < right:
        mid = (left + right) // 2

        # If mid and mid+1 are equal, unique element is in the right half
        if arr[mid] == arr[mid + 1]:
            left = mid + 1
        else:
            # If mid and mid+1 are different, unique element is at mid or in the left half
            right = mid

    return arr[left]

def search(arr):
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        if mid == len(arr) - 1:
            return arr[mid]

        if mid > 0 and arr[mid] != arr[mid - 1] and arr[mid] != arr[mid + 1]:
            return arr[mid]

        if mid % 2 == 0 and arr[mid] == arr[mid + 1]:
            left = mid + 2
        elif mid % 2 == 1 and arr[mid] == arr[mid - 1]:
            right = mid - 2
        else:
            left = mid + 1

    return arr[left]

