def search_element(arr):
    """
    Find the element that appears only once in a sorted array where all other
    elements appear twice. Uses binary search for O(log n) time complexity.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is the unique element
        if mid == 0:
            if arr[mid] != arr[mid + 1]:
                return arr[mid]
            else:
                left = mid + 1
        elif mid == len(arr) - 1:
            if arr[mid] != arr[mid - 1]:
                return arr[mid]
            else:
                right = mid - 1
        else:
            if arr[mid] == arr[mid + 1]:
                left = mid + 1
            elif arr[mid] == arr[mid - 1]:
                right = mid - 1
            else:
                return arr[mid]

    return arr[left]

