        mid = (left + right) // 2

        if mid % 2 == 0:
            # Even index: compare with next element
            if nums[mid] == nums[mid + 1]:
                left = mid + 1
            else:
                right = mid
        else:
            # Odd index: compare with previous element
            if nums[mid] == nums[mid - 1]:
                left = mid + 1
            else:
                right = mid

    return nums[left]

