    """
    Remove first and last occurrence of a given character from the string.

    Args:
        s: Input string
        char: Character to remove

    Returns:
        String with first and last occurrence of the character removed
    """
    if not s:
        return s

    first_index = s.find(char)
    last_index = s.rfind(char)

    if first_index == -1 or last_index == -1:
        return s

    if first_index == last_index:
        # Only one occurrence
        return s[:first_index] + s[first_index+1:]
    else:
        # Remove first and last occurrence
        if first_index == 0 and last_index == len(s) - 1:
            return s[1:-1]
        elif first_index == 0:
            return s[1:last_index]
        elif last_index == len(s) - 1:
            return s[first_index+1:]
        else:
            return s[:first_index] + s[first_index+1:last_index] + s[last_index+1:]

