        return False
    # Formula for octagonal numbers: O_n = n(3n-2)
    # Given O_k = n, we solve: n = k(3k-2)
    # 3k^2 - 2k - n = 0
    # Using quadratic formula: k = (2 ± sqrt(4 + 12n)) / 6
    # Since k must be positive: k = (2 + sqrt(4 + 12n)) / 6
    import math
    discriminant = 4 + 12 * n
    if discriminant < 0:
        return False
