def sequence(n):
    if n == 1:
        return 1

    sequence = [0] * (n + 1)
    sequence[1] = 1

    for i in range(2, n + 1):
        sequence[i] = sequence[i - sequence[i - 1]] + sequence[i - sequence[i - 1] - 1]

    return sequence[n]

def sequence(n):
    if n == 1:
        return 1
    if n == 2:
        return 2
    return sequence(n - 1) + sequence(n - sequence(n - 1))

def sequence(n):
    if n == 1:
        return 1
    if n == 2:
        return 2

    sequence = [0, 1, 2]  # 0-indexed, so index 0 is unused
    while len(sequence) < n + 1:
        next_val = sequence[n - 1]
        if next_val == 0:
            next_val = sequence[n - 2]
        else:
            next_val = sequence[n - 2]
        sequence.append(next_val)

    return sequence[n]

def sequence(n):
