def sequence(n):
    if n <= 0:
        return 0

    seq = [0] * (n + 1)
    seq[1] = 1

    for i in range(2, n + 1):
        seq[i] = seq[seq[i - 1]] if i - 1 > 0 else seq[i - 1]

    return seq[n]

def sequence(n):
    if n == 1:
        return 1
    if n == 2:
        return 2
    prev = sequence(n - 1)
    prev_prev = sequence(n - 2)
    return prev + prev_prev if prev > prev_prev else prev_prev + prev

