def is_undulating(n):
    """
    Check if a number is undulating (alternating up and down).

    An undulating number alternates between increasing and decreasing.
    For example: 1212121 -> 1<2>1<2>1<2>1<2 (True)
    """
    s = str(n)
    if len(s) < 2:
        return False

    for i in range(len(s) - 1):
        curr = int(s[i])
        next_val = int(s[i+1])

        if curr == next_val:
            return False

        # Check if direction alternates
        if i == 0:
            direction = curr < next_val
        else:
            prev_direction = (int(s[i-1]) < int(s[i]))
            if direction == prev_direction:
                return False
            direction = curr < next_val

    return True

