def snake_to_camel(snake_case_string):
    """
    Convert a snake case string to camel case string.

    Args:
        snake_case_string (str): Input string in snake case format

    Returns:
        str: Output string in camel case format
    """
    if not snake_case_string:
        return snake_case_string

    result = snake_case_string[0].upper()
    for char in snake_case_string[1:]:
        if char == '_':
            continue
        elif char.isupper():
            result += char
        else:
            result += char.lower()
    return result

