def odd_Equivalent(s, n):
    """
    Find the number of numbers with an odd value when rotating a binary string 
    the given number of times.

    Args:
        s (str): Binary string
        n (int): Number of rotations

    Returns:
        int: Number of odd values when rotating
    """
    def count_ones(s):
        return s.count('1')

    def rotate(s, times):
        return s[-times:] + s[:-times]

    count = 0
    for i in range(n + 1):
        rotated = rotate(s, i)
        if count_ones(rotated) % 2 == 1:
            count += 1

    return count

