def search(arr):
    """
    Find the element that appears only once in a sorted array.

    Args:
        arr: A sorted list of integers where exactly one element appears once
             and all other elements appear exactly twice.

    Returns:
        The single element that appears only once.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # Ensure mid is even to check pairs correctly
        if mid % 2 == 0:
            # If arr[mid] == arr[mid+1], the single element is in the right half
            if arr[mid] == arr[mid + 1]:
                left = mid + 2
            else:
                right = mid
        else:
            # If mid is odd, check with mid-1
            if arr[mid] == arr[mid - 1]:
                left = mid + 1
            else:
                right = mid - 2

    return arr[left]

