def search(arr):
    """
    Find the element that appears only once in a sorted array.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is the unique element
        if arr[mid] != arr[mid - 1] and arr[mid] != arr[mid + 1]:
            return arr[mid]

        # If mid is the first occurrence of a pair, search left
        if mid % 2 == 0:
            if arr[mid] == arr[mid + 1]:
                left = mid + 1
            else:
                right = mid
        else:
            if arr[mid] == arr[mid - 1]:
                left = mid + 1
            else:
                right = mid - 1

    return arr[left]

