    """
    Find the maximum difference between the number of 0s and number of 1s
    in any substring of the given binary string.
    """
    if not s:
        return 0

    max_diff = float('-inf')
    current_diff = 0

    for char in s:
        if char == '0':
            current_diff += 1
        else:
            current_diff -= 1

        if current_diff > max_diff:
            max_diff = current_diff

    # Also check the absolute difference (in case more 1s than 0s)
    max_diff = abs(max_diff)

    return max_diff

