def is_majority(arr, n, element):
    """
    Check if the element is the majority element in a sorted array.
    A majority element occurs more than n/2 times.
    """
    if n == 0:
        return False

    # In a sorted array, majority element must be at index n//2
    # because it occupies more than half the array
    if arr[n // 2] != element:
        return False

    # Count occurrences of the element
    left = 0
    right = n - 1

    while left <= n // 2:
        if arr[left] == element:
            left += 1
        else:
            break

    while right >= n // 2:
        if arr[right] == element:
            right -= 1
        else:
            break

    count = right - left + 1
    return count > n // 2

def is_majority(arr, n, element):
    # Use binary search to find the first occurrence of the element
    left, right = 0, n - 1

    # Binary search for first occurrence
    first_occurrence = -1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == element:
            first_occurrence = mid
            right = mid - 1
        elif arr[mid] < element:
            left = mid + 1
        else:
            right = mid - 1

    if first_occurrence == -1:
        return False

    # Binary search for last occurrence
    left, right = 0, n - 1
    last_occurrence = -1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == element:
            last_occurrence = mid
            left = mid + 1
        elif arr[mid] < element:
            left = mid + 1
        else:
            right = mid - 1

    if last_occurrence == -1:
        return False

    # Check if the count is more than n/2
    count = last_occurrence - first_occurrence + 1
    return count > n // 2

